1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type Step =
5	  | { op: "quote"; items: Item[] }
6	  | { op: "claim"; policy: number; incident: Incident };
7	type ScenarioInput = {
8	  customer: { yearsWithMHPCO: number };
9	  steps: Step[];
10	};
11	
12	const PROCESSING_FEE = 5;
13	const DEDUCTIBLE_PER_DAMAGE = 100;
14	const CAP_MULTIPLIER = 2;
15	const COMPONENT_INSURANCE_VALUE = 250;
16	const ITEM_INSURANCE_VALUE: Record<string, number> = {
17	  sword: 1000,
18	  amulet: 600,
19	  staff: 800,
20	  potion: 400,
21	};
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_DISCOUNT_RATE = 0.2;
26	const LOYALTY_YEARS_THRESHOLD = 2;
27	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
28	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
29	const COMPONENT_BASE = 25;
30	const COMPONENT_BLOCK_BASE = 60;
31	const COMPONENT_BLOCK_SIZE = 3;
32	const ITEM_BASE_PREMIUM: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	};
38	
39	function componentBaseFor(count: number): number {
40	  return count === COMPONENT_BLOCK_SIZE
41	    ? COMPONENT_BLOCK_BASE
42	    : count * COMPONENT_BASE;
43	}
44	
45	function policyBase(items: Item[]): number {
46	  const componentCounts: Record<string, number> = {};
47	  let base = 0;
48	  for (const item of items) {
49	    if (COMPONENT_TYPES.has(item.type)) {
50	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
51	    } else {
52	      base += ITEM_BASE_PREMIUM[item.type];
53	    }
54	  }
55	  for (const count of Object.values(componentCounts)) {
56	    base += componentBaseFor(count);
57	  }
58	  return base;
59	}
60	
61	function surchargeOn(
62	  items: Item[],
63	  rate: number,
64	  applies: (item: Item) => boolean,
65	): number {
66	  let total = 0;
67	  for (const item of items) {
68	    if (applies(item)) {
69	      total += ITEM_BASE_PREMIUM[item.type] * rate;
70	    }
71	  }
72	  return total;
73	}
74	
75	const isCursed = (item: Item): boolean => item.cursed === true;
76	const isHighlyEnchanted = (item: Item): boolean =>
77	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
78	
79	function quotePremium(
80	  customer: { yearsWithMHPCO: number },
81	  items: Item[],
82	  quoteIndex: number,
83	): number {
84	  const base = policyBase(items);
85	  // First-insurance is +10% on the base; use integer tenths to avoid float drift.
86	  const withFirstInsurance = (base * 11) / 10;
87	  const surcharges =
